<?php
 declare(strict_types=1); namespace tapmeppe\composer\helpers; use Illuminate\Support\Facades\{Blade, Event}; use tapmeppe\composer\blueprint\Resources; class Views extends \Illuminate\Support\ServiceProvider { public function boot() { if ($this->app->runningInConsole() || Abcd::isDevelopment()) $this->publishes( [__DIR__ . '/../assets' => public_path('extensions/governance/assets'),], 'public' ); $this->loadViewsFrom(__DIR__ . '/../views', 'governance'); switch (Abcd::getTool()) { case 'contacts': self::loadViewsViaEvent(['admin.layout.body.after'], ['admin.layout.head']); break; case 'marketing': self::loadViewsViaFactory('sendportal::layouts.app', 'sendportal::layouts.base'); break; case 'accounting': case 'laravel': default: self::loadViewsViaComponent(); } } static function printHubLayout(string $position) { echo Resources::read(dirname(__DIR__, 6) . "/layout.$position.html"); } private static function loadViewsViaComponent(...$folders) { Blade::component('governance::body', 'governance-body'); Blade::component('governance::head', 'governance-head'); } private static function loadViewsViaEvent(array $body, array $head) { foreach ($body as $event) Event::listen( $event, fn($handler) => $handler->addTemplate('governance::body') ); foreach ($head as $event) Event::listen( $event, fn($handler) => $handler->addTemplate('governance::head') ); } private static function loadViewsViaFactory(...$events) { $view = view(); foreach ($events as $event) $view->composer($event, function ($view) { $factory = $view->getFactory(); $factory->startPush('css', view('governance::head')->render()); $factory->stopPush(); $factory->startPush('js', view('governance::body')->render()); $factory->stopPush(); }); } } 